/* ❌ 不使用群组选择器时的冗余写法 */
h1 {
  color: #333;
  font-family: Arial;
}
h2 {
  color: #333;
  font-family: Arial;
}
p.special {
  color: #333;
  font-family: Arial;
}

/* ✅ 使用群组选择器的高效写法 */
h1, h2, p.special {
  color: #333;
  font-family: Arial;
}

/* 1. 英文关键字表示法 */
h1 {
  color: red; /* 简单直观，但可选颜色太少（约140种） */
}

/* 2. 十六进制（HEX）表示法（推荐⭐️） */
h2 {
  color: #FF5733; /* 最常用的网页取色模式，由6位0-F的字符组成 */
}

/* 3. RGB 表示法 */
h3 {
  color: rgb(255, 87, 51); /* 红绿蓝三原色，取值 0 - 255 */
}

/* 4. RGBA 表示法（带透明度） */
h4 {
  color: rgba(255, 87, 51, 0.5); /* 最后一个参数A(Alpha)代表不透明度，0全透，1不透 */
}

body {
  /* 1. 设置保底背景色（当图片加载失败或加载中时显示） */
  background-color: #1a1a1a;

  /* 2. 引入背景图片（使用 url() 函数封装路径） */
  background-image: url('images/night-sky.jpg');

  /* 3. 告诉图片不要像瓷砖一样重复拼贴 */
  background-repeat: no-repeat;

  /* 4. 让图片在屏幕中永远水平和垂直居中 */
  background-position: center center;

  /* 5. CSS3新特性：让图片根据比例拉伸，恰好覆盖整个全屏！ */
  background-size: cover;
}

/* ❌ 传统写法：代码长，占了4行 */
.header {
  background-color: #f0f0f0;
  background-image: url('logo.png');
  background-repeat: no-repeat;
  background-position: center top;
}

/* ✅ 复合简写法：一句搞定全部，酷炫且高效！ */
.header {
  /* 语法顺序一般不强求，但习惯上：颜色 图片 平铺 位置 */
  background: #f0f0f0 url('logo.png') no-repeat center top;
}

/* 最佳实践：设置多级备用字体 */
body {
  font-family: "Helvetica Neue", Helvetica, Arial, "Microsoft YaHei", sans-serif;
}

.article-content {
  /* 文本对齐方式：常用 left(左对齐), center(居中), right(右对齐), justify(两端对齐) */
  text-align: justify; 

  /* 首行缩进：2em 代表缩进正好两个中文字符的宽度 */
  text-indent: 2em;

  /* 行高（行间距）：1.6 代表行高是字体的 1.6 倍。非常舒适的阅读体验！ */
  line-height: 1.6;

  /* 字间距：增加英文字母或中文字符之间的距离 */
  letter-spacing: 1px;
}

body.text:
代码示例：制作一个漂亮的居中按钮
.btn {
  height: 50px;
  line-height: 50px; /* 让行高=高度，完成垂直居中 */
  text-align: center; /* 完成水平居中 */
  background-color: #007bff;
}

