.movie-card {
  background-color: #222;    /* 基础背景色深灰 */
  border-radius: 10px;       /* CSS3新属性：圆角10像素 */
  overflow: hidden;          /* 隐藏超出圆角的图片尖角 */
  width: 300px;              /* 固定卡片宽度 */
}

.movie-title {
  color: #fff;               /* 标题白色 */
  text-align: center;        /* 文本居中 */
  font-size: 20px;           /* 字体放大 */
  padding: 15px 0;           /* 上下留白 */
}

.movie-desc {
  color: #aaa;               /* 正文浅灰，降低对比度 */
  line-height: 1.6;          /* 增加行高，阅读舒适 */
  text-indent: 2em;          /* 首行缩进两格 */
  padding: 0 15px;           /* 左右不要贴死边框 */
}

.play-btn {
  display: block;            /* 转换区块以设置居中 */
  background-color: #e50914; /* 采用网飞经典的红色 */
  color: white;
  text-decoration: none;     /* 去掉下划线！ */
  text-align: center;
  line-height: 40px;         /* 行高=高度，文字垂直居中神技 */
  margin: 20px 15px;         /* 外边距推开距离 */
  border-radius: 20px;       /* 大圆角变药丸状按钮 */
}

/* 画龙点睛：交互反馈 */
.play-btn:hover {
  background-color: #ff1f2a; /* 悬停时颜色变亮 */
}
